private handleWatcherEvents(dir: string, err: Error | null, events: Event[]): void {
  if (err) {
    this.onError(new Error(`Watcher error for ${dir}`, { cause: err }))
    return
  }
  for (const event of events) {
    if (this.extensions !== null && !this.extensions.has(extname(event.path).toLowerCase())) {
      continue
    }
    try {
      this.onChange({ filePath: event.path, type: event.type })
    } catch (callbackError) {
      this.onError(new Error('FolderMonitor onChange callback failed', { cause: callbackError }))
    }
  }
}

async start(): Promise<void> {
  ...
  for (const dir of this.watchPaths) {
    try {
      const sub = await watcher.subscribe(dir, (err, events) => this.handleWatcherEvents(dir, err, events))
      this.subscriptions.push(sub)
    } catch (error) {
      this.onError(new Error(`Failed to watch directory: ${dir}`, { cause: error }))
    }
  }
}

WHY: Extracting the callback reduces nesting in start() from 4 to 2 levels and gives the event-handling logic a descriptive name. The extracted method is independently testable.

